import{_ as i,o as t,c as r,a6 as s,kW as a,kX as p,gg as o,eq as n,gy as e,kY as g,kZ as u,k_ as d,k$ as c,eD as h,eE as m}from"./chunks/framework.UYVGz2W_.js";const T=JSON.parse('{"title":"チームの準備","description":"","frontmatter":{},"headers":[],"relativePath":"ja/team/index.md","filePath":"ja/team/index.md"}'),_={name:"ja/team/index.md"};function P(b,l,f,k,x,K){return t(),r("div",null,[...l[0]||(l[0]=[s('<h1 id="チームの準備" tabindex="-1">チームの準備 <a class="header-anchor" href="#チームの準備" aria-label="Permalink to “チームの準備”">​</a></h1><p>ワークフローを定義したので、次に、タスクを割り当てられる担当者を確保するためにチームを編成します。</p><p>Kitsuにユーザーを追加し、部署にリンクし、権限を付与し、最後に、作業を開始できるように本番チームに追加する方法を学びます。</p><h2 id="ユーザーの作成" tabindex="-1">ユーザーの作成 <a class="header-anchor" href="#ユーザーの作成" aria-label="Permalink to “ユーザーの作成”">​</a></h2><h3 id="ユーザーの作成と部署へのリンク" tabindex="-1">ユーザーの作成と部署へのリンク <a class="header-anchor" href="#ユーザーの作成と部署へのリンク" aria-label="Permalink to “ユーザーの作成と部署へのリンク”">​</a></h3><p>人にタスクを割り当てるには、まずKitsuでその人のアカウントを作成する必要があります。</p><p>警告 定義 Kitsuの他の機能と同様に、ユーザーには2つのライブラリがあります。</p><ul><li><strong>People Page</strong>（グローバルライブラリ）は、ユーザーの権限、契約、所属する部署を決定するために使用します。</li><li><strong>Team Page</strong>（プロダクションライブラリ）は、プロジェクトで作業しているユーザーを定義し、プロダクションへのアクセス権を提供するために使用します。 :::</li></ul><p>メインメニュー<strong>へ移動！ <a href="../img/getting-started/main_button.png">メインメニュー</a> 、</strong>スタジオ**セクションの下にある <strong>人</strong>ページを選択します。</p><p><img src="'+a+'" alt="人メニュー"></p><p>次に、<a href="../img/getting-started/add_employee.png">新しいユーザーを追加</a> ボタンをクリックします。</p><p><img src="'+p+'" alt="新しいユーザーの作成"></p><p>次に、以下の情報を入力するよう促されます。（ユーザーを作成するには、以下のフィールドが必須であることにご注意ください）</p><ul><li><ol><li>名前（<strong>必須</strong>）</li></ol></li><li><ol start="2"><li>姓</li></ol></li><li><ol start="3"><li>メールアドレス（<strong>必須</strong>）</li></ol></li><li><ol start="4"><li>電話番号</li></ol></li></ul><p>::: 危険 重要！ アカウントを作成するには、メールアドレスは必須であり、唯一のものでなければなりません。 :::</p><ul><li><ol start="5"><li>ユーザーをリンクする<strong>部署</strong>を1つまたは複数指定できます。</li></ol></li></ul><p>部署に割り当てられると、<strong>マイチェック</strong>ページに表示される内容も影響を受け、自分の部署に関連するタスクのみが表示されます。</p><p>最終的に、タイムシートページも同様に、ユーザーの部署内のタスクのみにフィルタリングされます。</p><p>::: 詳細 部署に関する詳細情報 ユーザーが部署にリンクされると、さまざまなオプションが利用可能になります。例えば、グローバルホームページで、ユーザーの部署の表示に直接アクセスできるようになります。</p><p>部署の管理責任者は、部署内のすべてのタスクにコメントを追加したり、同じ部署の人だけにタスクを割り当てることができます。</p><p><img src="'+o+'" alt="部門フィルタリングビュー"> ::::</p><ul><li><ol start="6"><li>役割： ここでユーザーの権限の役割を定義します（以下で説明します）。</li></ol></li><li><ol start="7"><li>アクティブ</li></ol></li></ul><p>このセクションでは、ユーザーを即座にアクティブにするかどうかを選択できます。ユーザーがすぐにKitsuにアクセスする必要がある場合は、これを「はい」に設定します。ただし、ユーザーを作成したいが、まだKitsuへのアクセス権を与える準備ができていない場合もあります（例えば、2週間後に作業を開始するアーティストのタスクをスケジュールしたい場合など）。この場合、ユーザーを作成してスケジュールし、作業を開始したらアクセス権を有効にすることができます。</p><p>::: 危険 重要！ 各ユーザーは、Kitsuにログインするために個別のアカウントが必要です。 :::</p><h2 id="権限ロール" tabindex="-1">権限ロール <a class="header-anchor" href="#権限ロール" aria-label="Permalink to “権限ロール”">​</a></h2><h3 id="権限ロールの理解" tabindex="-1">権限ロールの理解 <a class="header-anchor" href="#権限ロールの理解" aria-label="Permalink to “権限ロールの理解”">​</a></h3><p>::: 警告 定義 権限ロールは、システムまたはアプリケーション内でユーザーに付与される一連のアクセス権と特権を定義し、ユーザーが実行できるアクションとアクセスできるリソースを決定します。 :::</p><p>ロールは非常に重要ですので、それぞれのロールが何を行うのか、また、特定のチームメンバーに関連するロールがどれなのかを理解しておくと便利です。各ロールの詳細については、以下の各セクションをクリックしてください。</p><ul><li><strong>アーティスト</strong> ::: 詳細 アーティスト権限 アーティストは、自分が参加している制作物のみにアクセスできます。 自分に割り当てられたタスクについてのみ、コメントの追加、メディアのアップロード、ステータスの変更を行うことができます。 アクセスできるステータスは、スタジオマネージャーによってあらかじめ設定されたものに限られます。</li></ul><p><strong>アーティストは、以下の操作が可能です。</strong></p><ul><li>グローバルページおよびタスクタイプページで、個人用フィルタを作成する。</li><li>自分のコメントを編集する。</li><li>割り当てられたタスクのチェックリストを確認する。</li><li>ショットやアセットのプレイリストをその場で作成できるが、保存はできない。</li></ul><p><strong>できないこと：</strong></p><ul><li>クライアントのコメントを参照する。</li><li>割り当てられていないプロジェクト内のものにアクセスする。</li></ul><p>アーティストがKitsuにログインすると、最初に表示されるのは「マイタスク」ページです。</p><p><img src="'+n+'" alt="my task"> :::</p><ul><li><strong>Supervisor</strong> ::: 詳細 Supervisor 権限 部門のスーパーバイザーは、アーティスト権限を継承します。</li></ul><p>部門のスーパーバイザーは、担当する部門の以下の項目に対して読み取りおよび書き込みのアクセス権限を持ちます。 アセット、ショット、タスク、割り当て、統計、内訳、プレイリスト。</p><p><strong>次の操作が可能です。</strong></p><ul><li>同じ部署のチームアーティストにタスクを割り当てることができます。</li><li>すべてのタスクまたは自分の部署に関するコメントの投稿。</li><li>自分の部署のチェックリストの確認。</li><li>コメントの固定。</li><li>自分のコメントの編集。</li><li>スタジオまたはクライアントのプレイリストの追加/編集。</li><li>クライアントのコメントと承認の確認。</li><li>他の部署からのコメントの確認。</li><li>自分の部署のタイムシートの表示。</li></ul><p><strong>できないこと：</strong></p><ul><li>スタジオチーム、メインタイムシート、制作リストへのアクセス</li><li>タスクタイプ、タスクステータス、アセットタイプの定義</li><li>自分以外の部署へのコメントの投稿。自分以外の部署のアーティストを割り当てることはできません。 :::</li></ul><ul><li><strong>制作マネージャー</strong> ::: 詳細 制作マネージャー権限 制作マネージャーは部署スーパーバイザー権限を継承します。</li></ul><p>制作マネージャーは、割り当てられた制作物に対して読み取りおよび書き込みのアクセス権を持ち、これには アセット、ショット、タスク、割り当て、統計、内訳、プレイリストが含まれます。</p><p><strong>制作マネージャーは、以下の操作が可能です。</strong></p><ul><li>アセットおよびショットを手動で、またはCSVバッチインポートにより作成する。</li><li>制作物内の任意のタスクにコメントを投稿する。</li><li>制作物内の任意のコメントを編集する。</li><li>制作物内の任意のチェックリストを確認する。</li><li>制作中のコメントを固定する。</li><li>タスクの列を追加する。</li><li>タスクを削除または追加する。</li><li>スタジオまたはクライアント用のプレイリストを追加/編集する。</li><li>クライアントのコメントと検証を確認する。</li></ul><p><strong>できないこと：</strong></p><ul><li>スタジオページ、メインタイムシート、制作リストにアクセスする。</li><li>タスクタイプ、タスクステータス、アセットタイプを定義する。 :::</li></ul><ul><li><strong>スタジオマネージャー</strong> ::: 詳細 スタジオマネージャー/管理者の権限 スタジオマネージャーは、管理者と同様に、Kitsu内のすべての制作および設定に対して読み取りおよび書き込みのアクセス権限を持ちます。 その権限には以下が含まれます。</li></ul><p>制作の作成と編集</p><p>スタジオマネージャーは、新しい制作を作成し、その種類、FPS、アスペクト比、解像度を定義し、カバー画像を追加することができます。 また、制作の編集や削除も可能です。</p><h4 id="スタジオの管理" tabindex="-1">スタジオの管理 <a class="header-anchor" href="#スタジオの管理" aria-label="Permalink to “スタジオの管理”">​</a></h4><p>スタジオマネージャーは、スタジオ内のすべてにアクセスできます。</p><ul><li>すべての制作に対する読み取り/書き込みアクセス</li><li>グローバルタイムシートページへのアクセス</li><li>スタジオ内のすべてのユーザーの表示</li><li>メインスケジュールへのアクセス</li></ul><p>「People（ユーザー）」ページでは、スタジオマネージャーが<strong>各ユーザーの権限ロールを定義</strong>します。</p><p>また、以下の操作も可能です。</p><p>Kitsuのグローバルな側面をカスタマイズする：例えば、タスクの種類、タスクのステータス、アセットの種類を追加・変更する。 権限ロールを設定する スタジオ名をカスタマイズする、企業ロゴを追加する、1日の作業時間数などを定義するなど、スタジオの高レベル情報をカスタマイズする。 メディアをダウンロードする際に、オリジナルのファイル名を使用するかどうかを選択する。</p><h4 id="制作物の管理" tabindex="-1">制作物の管理 <a class="header-anchor" href="#制作物の管理" aria-label="Permalink to “制作物の管理”">​</a></h4><p>彼らは、貴社の Kitsu サイト上のすべての制作物にフルアクセスできます。 さらに、</p><ul><li>スーパーバイザーと同等の権限を持ちます。</li><li>タスクカラムの追加/削除が可能です。</li><li>カスタムメタデータカラムの作成が可能です。 :::</li></ul><ul><li><p><strong>ベンダー</strong> ::: 詳細 ベンダーの権限 ベンダーはアーティストとほぼ同等の権限を持ちます。主な違いは、アーティストは自分の制作物内のタスクを閲覧できる（ただし、自分に割り当てられたタスクのみ編集可能）のに対し、ベンダーは自分に割り当てられたタスクのみ閲覧・編集できることです。割り当てられていないその他のタスクはすべて非表示となります。 :::</p></li><li><p><strong>クライアント</strong> ::: 詳細 クライアント 権限 クライアントは、自身が関与している制作物のみを表示できます。</p></li></ul><p><strong>クライアントは以下の操作が可能です。</strong></p><ul><li>アセット/ショットのグローバルページにアクセスする。</li><li>統計ページにアクセスする。</li><li>クライアントのプレイリストにアクセスし、コメント投稿時にタスクステータスに制限付きでアクセスする</li></ul><p><strong>注記</strong></p><ul><li>クライアントのリテイクまたは検証ステータスを確認できるのは、スーパーバイザーとスタジオマネージャーのみです。</li></ul><p><strong>彼らはできません。</strong></p><ul><li>タスクの割り当てを見る</li><li>自分が書いていないコメントを見る :::</li></ul><p>::: 詳細 CSV スプレッドシートファイルから従業員を追加する</p><p>従業員リストがすでにスプレッドシートファイルで用意されているかもしれません。 Kitsu では、<code>.csv</code> ファイルを直接インポートするか、データを直接 Kitsu にコピー＆ペーストするかの 2 つの方法でインポートできます。</p><p>まず、スプレッドシートを <code>.csv</code> ファイルとして保存します。</p><p>次に、Kitsu の「People」ページに戻り、「<strong>インポート」</strong>アイコンをクリックします。 <img src="'+e+'" alt="インポートアイコン"></p><p>「<strong>CSV からデータをインポート」</strong>というポップアップウィンドウが開きます。「<strong>参照」</strong>をクリックして <code>.csv</code> ファイルを選択します。</p><p><img src="'+g+'" alt="インポートするCSVファイル"></p><p>結果を確認するには、<strong>[プレビュー]</strong>ボタンをクリックします。</p><p>データのプレビューを使用して、列名を確認し、調整することができます。</p><p><strong>注意：</strong> <strong>[役割]</strong>列は必須ではありません。</p><p><img src="'+u+'" alt="インポートするデータのコピー＆ペースト"></p><p>すべてが適切に表示されたら、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのユーザーがKitsuにインポートされました。</p><p><img src="'+d+'" alt="Import data copy paste data"></p><p>:::</p><h2 id="二要素認証" tabindex="-1">二要素認証 <a class="header-anchor" href="#二要素認証" aria-label="Permalink to “二要素認証”">​</a></h2><h3 id="スタジオにセキュリティを追加" tabindex="-1">スタジオにセキュリティを追加 <a class="header-anchor" href="#スタジオにセキュリティを追加" aria-label="Permalink to “スタジオにセキュリティを追加”">​</a></h3><p><strong>二要素認証</strong>は、Kitsuにログインするユーザーにセキュリティの追加レイヤーを提供します。ユーザーごとに有効にできるので、どのユーザーに適用するかを決定できます。</p><p>有効にするには、画面右上のアバターをクリックし、<strong>プロフィール</strong>を選択します。 ページの下部に、さまざまな<strong>二要素認証</strong>オプションが表示されます。</p><p>利用可能な二要素認証の方法</p><ul><li><strong>TOTP</strong>：これは、二要素認証アプリをアカウントの二次パスワードとして使用できるようにします。このオプションを選択すると、QRコードが表示されます。お好みの二要素認証アプリでこれをスキャンすると、ログインのたびにワンタイムコードが要求されます。</li><li><strong>OTP Via Email</strong> TOTP と同様ですが、2FA コードはアプリではなく、お客様のメールアドレスに送信されます</li><li><strong>FIDO Device</strong> FIDO デバイスとは、2 要素認証 (2FA) のための FIDO (Fast IDentity Online) 標準をサポートするハードウェアセキュリティキーを指します。 これらのデバイスのいずれかをお持ちの場合は、その名前をここに記入して 2 要素認証に使用することができます</li></ul><p><img src="'+c+'" alt="二要素認証"></p><h2 id="チームへのユーザーの追加" tabindex="-1">チームへのユーザーの追加 <a class="header-anchor" href="#チームへのユーザーの追加" aria-label="Permalink to “チームへのユーザーの追加”">​</a></h2><p>プロダクションを作成したら、ユーザーにアクセスを許可するために、プロダクションのチームにユーザーを追加する必要があります。 チームに所属することで、タスクを割り当てられるようにもなります。</p><p>::: ヒント 読み取り権限を与えるために、チームにスタジオマネージャーロールを追加する必要はありません（このロールには、いずれにしてもアクセス権があります）。ただし、タスクを割り当てる場合は、チームに追加する必要があります。 :::</p><p>ユーザーをチームに追加するには：</p><ol><li>プロダクションで、ページ上部のナビゲーションドロップダウンメニューを使用して、[チーム] ページを選択します。</li></ol><p><img src="'+h+'" alt="ドロップダウンメニューチーム"></p><ol start="2"><li><strong>チーム</strong>ページでは、特定のプロジェクトのすべての担当者を参照できます。別のプロジェクトチームを確認する場合は、ページの先頭に移動します。</li></ol><p><img src="'+m+'" alt="チームページ"></p>',95)])])}const v=i(_,[["render",P]]);export{T as __pageData,v as default};
